                  className="text-blue-100 text-sm sm:text-base font-medium"
                >
                  Welcome to your personalized HR dashboard
                </motion.p>
              </div>

              {/* Enhanced Time Display */}
              <motion.div 
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
