import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import dayjs from 'dayjs';
import { 
  Calendar, 
  Clock, 
  FileText, 
  CheckCircle, 
  AlertCircle, 
  Send,
  User,
  CalendarDays,
  Timer,
  MessageSquare,
  ArrowRight,
  Sparkles,
  Info
} from 'lucide-react';
import Navbar from '../components/Navbar';

const LeaveApply = ({ userData, setUserData }) => {
  const [leaveTypes, setLeaveTypes] = useState([]);
  const [form, setForm] = useState({
    leaveType: '',
    dayType: 'fullDay',
    date: '',
    fromDate: '',
    toDate: '',
    fromTime: '',
    toTime: '',
    reason: '',
    numDays: 0
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loadingLeaveTypes, setLoadingLeaveTypes] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);

  useEffect(() => {
    const fetchLeaveTypes = async () => {
      if (!userData?.ls_EMPTYPE) {
        setError('Employee data not available.');
        setLoadingLeaveTypes(false);
        return;
      }
      try {
        const res = await axios.get(`http://localhost:5000/api/leave-types?empType=${userData.ls_EMPTYPE}`);
        if (res.data?.success) {
          setLeaveTypes(res.data.leaveTypes);
        } else {
          setError(res.data.message || 'No leave types found.');
        }
      } catch (err) {
        setError('Failed to load leave types.');
      } finally {
        setLoadingLeaveTypes(false);
      }
    };
    fetchLeaveTypes();
  }, [userData]);

  const formatDate = (date) => dayjs(date).format('YYYYMMDD');

  const handleChange = (e) => {
    const { name, value } = e.target;
    let updated = { ...form, [name]: value };
    setError('');
    setSuccess('');

    if (name === 'dayType') {
      updated = {
        ...updated,
        fromDate: '',
        toDate: '',
        date: '',
        fromTime: '',
        toTime: '',
        numDays: value === 'halfDay' ? 0.5 : value === 'fullDay' ? 1 : 0
      };
    }

    // Auto-set dates for full day leave
    if (name === 'date' && updated.dayType === 'fullDay') {
      updated.fromDate = value;
      updated.toDate = value;
      updated.numDays = 1;
    }

    // Calculate half day duration
    if ((name === 'fromTime' || name === 'toTime') && form.dayType === 'halfDay') {
      if (updated.fromTime && updated.toTime) {
        const [fh, fm] = updated.fromTime.split(':').map(Number);
        const [th, tm] = updated.toTime.split(':').map(Number);
        const fromMinutes = fh * 60 + fm;
        const toMinutes = th * 60 + tm;
        const duration = toMinutes - fromMinutes;

        if (duration <= 0) {
          setError('End time must be after start time');
          updated.numDays = 0;
        } else {
          updated.numDays = Math.min(duration / 480, 0.5);
        }
      }
    }

    // Handle date changes for multi-day
    if ((name === 'fromDate' || name === 'toDate') && updated.dayType === 'multiDay') {
      if (updated.fromDate && updated.toDate) {
        const start = dayjs(updated.fromDate);
        const end = dayjs(updated.toDate);
        updated.numDays = end.isBefore(start) ? 0 : end.diff(start, 'day') + 1;
        if (end.isBefore(start)) setError('End date must be after start date');
      }
    }

    setForm(updated);
  };

  const validateForm = () => {
    if (!form.leaveType) {
      setError('Please select a leave type');
      return false;
    }

    if (['fullDay', 'halfDay'].includes(form.dayType) && !form.date) {
      setError('Please select a date');
      return false;
    }

    if (form.dayType === 'multiDay' && (!form.fromDate || !form.toDate)) {
      setError('Please select both start and end dates');
      return false;
    }

    if (form.dayType === 'halfDay' && (!form.fromTime || !form.toTime)) {
      setError('Please select both start and end times for half day');
      return false;
    }

    if (form.numDays <= 0) {
      setError('Invalid leave duration');
      return false;
    }

    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsSubmitting(true);
    try {
      let fromTime = '';
      let toTime = '';

      if (form.dayType === 'halfDay') {
        fromTime = form.fromTime;
        toTime = form.toTime;
      }

      let finalFromDate, finalToDate;
      if (form.dayType === 'multiDay') {
        finalFromDate = form.fromDate;
        finalToDate = form.toDate;
      } else {
        finalFromDate = form.date;
        finalToDate = form.date;
      }

      const res = await axios.post('http://localhost:5000/api/apply-leave', {
        ls_EmpCode: userData.ls_EMPCODE.toString(),
        ls_FromDate: formatDate(finalFromDate),
        ls_ToDate: formatDate(finalToDate),
        ls_DocDate: formatDate(dayjs()),
        ls_NofDays: form.numDays.toString(),
        ls_FromTime: form.dayType === 'halfDay' ? fromTime : '',
        ls_ToTime: form.dayType === 'halfDay' ? toTime : '',
        ls_LeavTyp: form.leaveType,
        ls_Reason: form.reason,
        ls_GrpNo: '5'
      });

      if (res.data?.success) {
        setSuccess(res.data.message || 'Leave applied successfully');
        setForm({
          leaveType: '',
          dayType: form.dayType,
          date: '',
          fromDate: '',
          toDate: '',
          fromTime: '',
          toTime: '',
          reason: '',
          numDays: 0
        });
      } else {
        setError(res.data?.message || 'Application failed. Please try again.');
      }
    } catch (err) {
      if (err.response) {
        setError(err.response.data?.message || 'Server error occurred');
      } else if (err.request) {
        setError('Network error. Please check your connection and try again.');
      } else {
        setError('An unexpected error occurred.');
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const today = dayjs().format('YYYY-MM-DD');

  const getStepProgress = () => {
    if (form.leaveType && form.dayType) {
      if (form.dayType === 'multiDay' && form.fromDate && form.toDate) return 3;
      if (['fullDay', 'halfDay'].includes(form.dayType) && form.date) {
        if (form.dayType === 'halfDay' && form.fromTime && form.toTime) return 3;
        if (form.dayType === 'fullDay') return 3;
      }
      return 2;
    }
    if (form.leaveType) return 2;
    return 1;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50">
      <Navbar setUserData={setUserData} userData={userData} />

      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Header Section */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center gap-3 mb-4">
            <div className="p-3 bg-gradient-to-r from-blue-500 to-purple-600 rounded-2xl">
              <FileText className="w-8 h-8 text-white" />
            </div>
            <div>
              <h1 className="text-4xl font-bold bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent">
                Apply for Leave
              </h1>
              <p className="text-gray-600 mt-1">Submit your time-off request with ease</p>
            </div>
          </div>

          {/* Progress Indicator */}
          <div className="flex items-center justify-center gap-2 mt-6">
            {[1, 2, 3].map((step) => (
              <div key={step} className="flex items-center">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-semibold transition-all duration-300 ${
                    getStepProgress() >= step
                      ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg'
                      : 'bg-gray-200 text-gray-500'
                  }`}
                >
                  {getStepProgress() >= step ? <CheckCircle className="w-5 h-5" /> : step}
                </div>
                {step < 3 && (
                  <div className={`w-12 h-1 mx-2 rounded transition-all duration-300 ${
                    getStepProgress() > step ? 'bg-gradient-to-r from-blue-500 to-purple-600' : 'bg-gray-200'
                  }`} />
                )}
              </div>
            ))}
          </div>

          <div className="flex justify-center gap-8 mt-4 text-sm">
            <span className={getStepProgress() >= 1 ? 'text-blue-600 font-medium' : 'text-gray-500'}>Leave Type</span>
            <span className={getStepProgress() >= 2 ? 'text-blue-600 font-medium' : 'text-gray-500'}>Duration</span>
            <span className={getStepProgress() >= 3 ? 'text-blue-600 font-medium' : 'text-gray-500'}>Review</span>
          </div>
        </div>

        {/* Alert Messages */}
        <AnimatePresence>
          {error && (
            <motion.div
              initial={{ opacity: 0, y: -10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: -10, scale: 0.95 }}
              className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 rounded-2xl shadow-sm"
            >
              <div className="flex items-center gap-3">
                <AlertCircle className="w-5 h-5 text-red-500 flex-shrink-0" />
                <p className="font-medium">{error}</p>
              </div>
            </motion.div>
          )}

          {success && (
            <motion.div
              initial={{ opacity: 0, y: -10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: -10, scale: 0.95 }}
              className="mb-6 p-4 bg-green-50 border border-green-200 text-green-700 rounded-2xl shadow-sm"
            >
              <div className="flex items-center gap-3">
                <CheckCircle className="w-5 h-5 text-green-500 flex-shrink-0" />
                <p className="font-medium">{success}</p>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Main Form Card */}
        <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
          <form onSubmit={handleSubmit} className="p-8 space-y-8">
            {/* Step 1: Leave Type Selection */}
            <div className="space-y-4">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-blue-100 rounded-xl">
                  <User className="w-5 h-5 text-blue-600" />
                </div>
                <div>
                  <h3 className="text-xl font-semibold text-gray-800">Select Leave Type</h3>
                  <p className="text-gray-500 text-sm">Choose the type of leave you want to apply for</p>
                </div>
              </div>

              <div className="relative">
                <select
                  name="leaveType"
                  value={form.leaveType}
                  onChange={handleChange}
                  className="w-full px-6 py-4 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all duration-200 bg-gray-50 hover:bg-white text-lg font-medium appearance-none cursor-pointer"
                  disabled={loadingLeaveTypes || isSubmitting}
                  required
                >
                  <option value="">
                    {loadingLeaveTypes ? 'Loading leave types...' : 'Select Leave Type'}
                  </option>
                  {leaveTypes.map(type => (
                    <option key={type.code} value={type.code}>
                      {type.name} ({type.code})
                    </option>
                  ))}
                </select>
                <div className="absolute right-4 top-1/2 transform -translate-y-1/2 pointer-events-none">
                  <ArrowRight className="w-5 h-5 text-gray-400 rotate-90" />
                </div>
              </div>
            </div>

            {/* Step 2: Duration Type Selection */}
            {form.leaveType && (
              <div className="space-y-6">
                <div className="flex items-center gap-3 mb-6">
                  <div className="p-2 bg-purple-100 rounded-xl">
                    <CalendarDays className="w-5 h-5 text-purple-600" />
                  </div>
                  <div>
                    <h3 className="text-xl font-semibold text-gray-800">Choose Duration</h3>
                    <p className="text-gray-500 text-sm">Select how long you need to be away</p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {/* Full Day Option */}
                  <label 
                    className={`group relative flex flex-col p-6 border-2 rounded-2xl cursor-pointer transition-all duration-200 ${
                      form.dayType === 'fullDay' 
                        ? 'border-blue-500 bg-blue-50 shadow-lg shadow-blue-100' 
                        : 'border-gray-200 hover:border-gray-300 hover:shadow-md'
                    }`}
                  >
                    <input
                      type="radio"
                      name="dayType"
                      value="fullDay"
                      checked={form.dayType === 'fullDay'}
                      onChange={handleChange}
                      className="sr-only"
                    />
                    <div className="flex items-center justify-between mb-3">
                      <Calendar className={`w-6 h-6 ${form.dayType === 'fullDay' ? 'text-blue-600' : 'text-gray-400'}`} />
                      <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                        form.dayType === 'fullDay' ? 'border-blue-500 bg-blue-500' : 'border-gray-300'
                      }`}>
                        {form.dayType === 'fullDay' && <div className="w-2 h-2 rounded-full bg-white"></div>}
                      </div>
                    </div>
                    <h4 className="font-semibold text-gray-800 mb-1">Full Day</h4>
                    <p className="text-sm text-gray-500">Complete day off</p>
                    <div className="mt-3 text-xs font-medium text-blue-600">1 day</div>
                  </label>

                  {/* Half Day Option */}
                  <label 
                    className={`group relative flex flex-col p-6 border-2 rounded-2xl cursor-pointer transition-all duration-200 ${
                      form.dayType === 'halfDay' 
                        ? 'border-purple-500 bg-purple-50 shadow-lg shadow-purple-100' 
                        : 'border-gray-200 hover:border-gray-300 hover:shadow-md'
                    }`}
                  >
                    <input
                      type="radio"
                      name="dayType"
                      value="halfDay"
                      checked={form.dayType === 'halfDay'}
                      onChange={handleChange}
                      className="sr-only"
                    />
                    <div className="flex items-center justify-between mb-3">
                      <Timer className={`w-6 h-6 ${form.dayType === 'halfDay' ? 'text-purple-600' : 'text-gray-400'}`} />
                      <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                        form.dayType === 'halfDay' ? 'border-purple-500 bg-purple-500' : 'border-gray-300'
                      }`}>
                        {form.dayType === 'halfDay' && <div className="w-2 h-2 rounded-full bg-white"></div>}
                      </div>
                    </div>
                    <h4 className="font-semibold text-gray-800 mb-1">Half Day</h4>
                    <p className="text-sm text-gray-500">Custom time range</p>
                    <div className="mt-3 text-xs font-medium text-purple-600">≤ 0.5 day</div>
                  </label>

                  {/* Multi-Day Option */}
                  <label 
                    className={`group relative flex flex-col p-6 border-2 rounded-2xl cursor-pointer transition-all duration-200 ${
                      form.dayType === 'multiDay' 
                        ? 'border-green-500 bg-green-50 shadow-lg shadow-green-100' 
                        : 'border-gray-200 hover:border-gray-300 hover:shadow-md'
                    }`}
                  >
                    <input
                      type="radio"
                      name="dayType"
                      value="multiDay"
                      checked={form.dayType === 'multiDay'}
                      onChange={handleChange}
                      className="sr-only"
                    />
                    <div className="flex items-center justify-between mb-3">
                      <CalendarDays className={`w-6 h-6 ${form.dayType === 'multiDay' ? 'text-green-600' : 'text-gray-400'}`} />
                      <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                        form.dayType === 'multiDay' ? 'border-green-500 bg-green-500' : 'border-gray-300'
                      }`}>
                        {form.dayType === 'multiDay' && <div className="w-2 h-2 rounded-full bg-white"></div>}
                      </div>
                    </div>
                    <h4 className="font-semibold text-gray-800 mb-1">Multi-Day</h4>
                    <p className="text-sm text-gray-500">Extended leave</p>
                    <div className="mt-3 text-xs font-medium text-green-600">Multiple days</div>
                  </label>
                </div>
              </div>
            )}

            {/* Step 3: Date and Time Selection */}
            {form.leaveType && form.dayType && (
              <div className="space-y-6">
                <div className="flex items-center gap-3 mb-6">
                  <div className="p-2 bg-green-100 rounded-xl">
                    <Clock className="w-5 h-5 text-green-600" />
                  </div>
                  <div>
                    <h3 className="text-xl font-semibold text-gray-800">Select Dates & Times</h3>
                    <p className="text-gray-500 text-sm">Specify when you need time off</p>
                  </div>
                </div>

                {/* Half Day Time Selection */}
                {form.dayType === 'halfDay' && (
                  <div className="bg-gradient-to-r from-purple-50 to-blue-50 rounded-2xl p-6">
                    <div className="flex items-center gap-2 mb-4">
                      <Timer className="w-5 h-5 text-purple-600" />
                      <h4 className="font-semibold text-gray-800">Custom Time Range</h4>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                          From Time
                        </label>
                        <input
                          type="time"
                          name="fromTime"
                          value={form.fromTime}
                          onChange={handleChange}
                          className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 transition-all duration-200"
                          required
                          disabled={isSubmitting}
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                          To Time
                        </label>
                        <input
                          type="time"
                          name="toTime"
                          value={form.toTime}
                          onChange={handleChange}
                          className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 transition-all duration-200"
                          required
                          disabled={isSubmitting}
                        />
                      </div>
                    </div>
                    {form.fromTime && form.toTime && (
                      <div className="mt-4 p-3 bg-white border border-purple-200 rounded-xl">
                        <div className="flex items-center gap-2">
                          <Info className="w-4 h-4 text-purple-600" />
                          <p className="text-sm font-medium text-purple-800">
                            Half day from {form.fromTime} to {form.toTime}
                          </p>
                        </div>
                      </div>
                    )}
                  </div>
                )}

                {/* Date Selection */}
                {form.dayType === 'multiDay' ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        From Date
                      </label>
                      <input
                        type="date"
                        name="fromDate"
                        value={form.fromDate}
                        onChange={handleChange}
                        min={today}
                        className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-green-100 focus:border-green-500 transition-all duration-200"
                        required
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        To Date
                      </label>
                      <input
                        type="date"
                        name="toDate"
                        value={form.toDate}
                        onChange={handleChange}
                        min={form.fromDate || today}
                        className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-green-100 focus:border-green-500 transition-all duration-200"
                        required
                      />
                    </div>
                  </div>
                ) : (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Date
                    </label>
                    <input
                      type="date"
                      name="date"
                      value={form.date}
                      onChange={handleChange}
                      min={today}
                      className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all duration-200"
                      required
                    />
                  </div>
                )}

                {/* Summary Card */}
                {((form.dayType === 'multiDay' && form.fromDate && form.toDate) || 
                  (['fullDay', 'halfDay'].includes(form.dayType) && form.date)) && (
                  <div className="bg-gradient-to-r from-blue-50 to-purple-50 border border-blue-200 rounded-2xl p-6">
                    <div className="flex items-center gap-3 mb-3">
                      <Sparkles className="w-5 h-5 text-blue-600" />
                      <h4 className="font-semibold text-gray-800">Leave Summary</h4>
                    </div>
                    <div className="space-y-2 text-sm">
                      <div className="flex justify-between">
                        <span className="text-gray-600">Duration:</span>
                        <span className="font-semibold text-gray-800">
                          {form.numDays} {form.numDays === 1 ? 'day' : 'days'}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-gray-600">Type:</span>
                        <span className="font-semibold text-gray-800">
                          {form.dayType === 'fullDay' ? 'Full Day' : 
                           form.dayType === 'halfDay' ? 'Half Day' : 'Multi-Day'}
                        </span>
                      </div>
                      {form.dayType === 'fullDay' && form.date && (
                        <div className="flex justify-between">
                          <span className="text-gray-600">Date:</span>
                          <span className="font-semibold text-gray-800">
                            {dayjs(form.date).format('MMMM D, YYYY')}
                          </span>
                        </div>
                      )}
                      {form.dayType === 'halfDay' && form.fromTime && form.toTime && (
                        <div className="flex justify-between">
                          <span className="text-gray-600">Time:</span>
                          <span className="font-semibold text-gray-800">
                            {form.fromTime} - {form.toTime}
                          </span>
                        </div>
                      )}
                      {form.dayType === 'multiDay' && form.fromDate && form.toDate && (
                        <div className="flex justify-between">
                          <span className="text-gray-600">Dates:</span>
                          <span className="font-semibold text-gray-800">
                            {dayjs(form.fromDate).format('MMM D')} - {dayjs(form.toDate).format('MMM D, YYYY')}
                          </span>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Reason Section */}
            {form.leaveType && form.dayType && (
              <div className="space-y-4">
                <div className="flex items-center gap-3 mb-4">
                  <div className="p-2 bg-orange-100 rounded-xl">
                    <MessageSquare className="w-5 h-5 text-orange-600" />
                  </div>
                  <div>
                    <h3 className="text-lg font-semibold text-gray-800">Reason (Optional)</h3>
                    <p className="text-gray-500 text-sm">Brief description of your leave</p>
                  </div>
                </div>
                <textarea
                  name="reason"
                  placeholder="Enter reason for leave (optional)"
                  value={form.reason}
                  onChange={handleChange}
                  rows="4"
                  className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-orange-100 focus:border-orange-500 transition-all duration-200 resize-none"
                />
              </div>
            )}

            {/* Submit Button */}
            {form.leaveType && form.dayType && (
              <div className="pt-6">
                <button
                  type="submit"
                  disabled={isSubmitting}
                  className={`w-full group relative overflow-hidden py-4 px-6 rounded-2xl font-semibold text-white transition-all duration-300 ${
                    isSubmitting ? 'bg-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 shadow-lg hover:shadow-xl'
                  }`}
                >
                  <div className="flex items-center justify-center gap-3">
                    {isSubmitting ? (
                      <>
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        Processing Application...
                      </>
                    ) : (
                      <>
                        <Send className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                        Submit Leave Application
                      </>
                    )}
                  </div>
                </button>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default LeaveApply;

client/src/pages/LeaveHistory.jsx.content:
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import dayjs from 'dayjs';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import { 
  Search, 
  Filter, 
  Calendar, 
  CheckSquare, 
  Square, 
  TrendingUp,
  Clock,
  CheckCircle,
  XCircle,
  AlertCircle,
  Eye,
  Download,
  RefreshCw,
  BarChart3,
  Users,
  FileText,
  Sparkles
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const LeaveHistory = ({ userData, setUserData }) => {
  const [leaveData, setLeaveData] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({
    checked: false,
    status: 'ALL',
    date: dayjs().format('YYYY-MM-DD')
  });
  const [viewMode, setViewMode] = useState('table'); // 'table' or 'cards'
  const [searchTerm, setSearchTerm] = useState('');

  const statusOptions = [
    { value: 'ALL', label: 'All Status', icon: FileText, color: 'gray' },
    { value: 'A', label: 'Approved', icon: CheckCircle, color: 'green' },
    { value: 'P', label: 'Pending', icon: Clock, color: 'yellow' },
    { value: 'R', label: 'Rejected', icon: XCircle, color: 'red' }
  ];

  const fetchLeaveHistory = async () => {
    if (!userData?.ls_EMPCODE) {
      setError('Employee Code missing.');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const formattedDate = dayjs(filters.date).format('YYYYMMDD');
      const checkedValue = filters.checked ? 'Y' : 'N';

      const res = await axios.get(
        `http://localhost:5000/api/leave-history`,
        {
          params: {
            ls_EmpCode: userData.ls_EMPCODE,
            ls_DocDate: formattedDate,
            ls_Check: checkedValue,
            ls_Status: filters.status,
          },
        }
      );

      if (res.data?.success) {
        const history = res.data.leaveHistory;
        if (Array.isArray(history) && history.length > 0) {
          setLeaveData(history);
        } else {
          setLeaveData([]);
          setError('No leave history found for the selected criteria.');
        }
      } else {
        setError(res.data?.message || 'Failed to fetch leave history.');
      }
    } catch (err) {
      console.error(err);
      setError('Failed to fetch leave history.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLeaveHistory();
  }, [userData, filters]);

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({
      ...prev,
      [key]: value
    }));
  };

  const getStatusBadge = (status) => {
    const statusMap = {
      'A': { 
        label: 'Approved', 
        class: 'bg-green-100 text-green-800 border border-green-200',
        icon: CheckCircle,
        color: 'text-green-600'
      },
      'P': { 
        label: 'Pending', 
        class: 'bg-yellow-100 text-yellow-800 border border-yellow-200',
        icon: Clock,
        color: 'text-yellow-600'
      },
      'R': { 
        label: 'Rejected', 
        class: 'bg-red-100 text-red-800 border border-red-200',
        icon: XCircle,
        color: 'text-red-600'
      }
    };

    const statusInfo = statusMap[status] || { 
      label: status || 'Unknown', 
      class: 'bg-gray-100 text-gray-800 border border-gray-200',
      icon: AlertCircle,
      color: 'text-gray-600'
    };

    const IconComponent = statusInfo.icon;

    return (
      <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium ${statusInfo.class}`}>
        <IconComponent className={`w-3.5 h-3.5 ${statusInfo.color}`} />
        {statusInfo.label}
      </span>
    );
  };

  const filteredData = leaveData.filter(item =>
    item.leaveName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.leaveType?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.reason?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const calculateStats = () => {
    const stats = {
      total: filteredData.length,
      approved: filteredData.filter(item => item.status === 'A').length,
      pending: filteredData.filter(item => item.status === 'P').length,
      rejected: filteredData.filter(item => item.status === 'R').length,
      totalUsed: filteredData.reduce((sum, item) => sum + (parseFloat(item.usedLeave) || 0), 0),
      totalAvailable: filteredData.reduce((sum, item) => sum + (parseFloat(item.openLeave) || 0), 0)
    };
    stats.totalBalance = stats.totalAvailable - stats.totalUsed;
    return stats;
  };

  const stats = calculateStats();

  // Animation variants
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
        delayChildren: 0.2
      }
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.3, ease: "easeOut" }
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100">
      <Navbar setUserData={setUserData} userData={userData} />

      <motion.div 
        className="max-w-7xl mx-auto px-4 sm:px-6 py-6 sm:py-8"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {/* Enhanced Header */}
        <motion.div variants={cardVariants} className="mb-8">
          <div className="bg-gradient-to-r from-blue-600 via-purple-600 to-indigo-700 text-white rounded-2xl p-6 sm:p-8 shadow-xl">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
              <div>
                <div className="flex items-center gap-3 mb-2">
                  <div className="p-2 bg-white/20 rounded-xl">
                    <BarChart3 className="w-6 h-6" />
                  </div>
                  <h1 className="text-2xl sm:text-3xl font-bold">Leave History</h1>
                </div>
                <p className="text-blue-100">Track and analyze your leave applications</p>
              </div>
              <div className="mt-4 sm:mt-0 flex gap-2">
                <motion.button
                  onClick={() => fetchLeaveHistory()}
                  disabled={loading}
                  className="flex items-center gap-2 bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-xl transition-all"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  Refresh
                </motion.button>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Stats Cards */}
        <motion.div variants={cardVariants} className="grid grid-cols-2 lg:grid-cols-6 gap-4 mb-8">
          <StatsCard icon={FileText} label="Total Leaves" value={stats.total} color="blue" />
          <StatsCard icon={CheckCircle} label="Approved" value={stats.approved} color="green" />
          <StatsCard icon={Clock} label="Pending" value={stats.pending} color="yellow" />
          <StatsCard icon={XCircle} label="Rejected" value={stats.rejected} color="red" />
          <StatsCard icon={TrendingUp} label="Total Used" value={stats.totalUsed.toFixed(1)} color="purple" />
          <StatsCard icon={Sparkles} label="Balance" value={stats.totalBalance.toFixed(1)} color="indigo" />
        </motion.div>

        {/* Enhanced Filters */}
        <motion.div variants={cardVariants} className="bg-white rounded-2xl shadow-xl border border-gray-100 p-6 mb-8">
          <div className="flex items-center gap-4 mb-6">
            <div className="p-2 bg-blue-100 rounded-xl">
              <Filter className="w-5 h-5 text-blue-600" />
            </div>
            <h2 className="text-xl font-semibold text-gray-900">Filters & Search</h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-4">
            {/* Search */}
            <div className="lg:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <Search className="w-4 h-4 inline mr-1" />
                Search Leaves
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Search by leave type, name, or reason..."
                  className="w-full border border-gray-300 rounded-xl px-4 py-3 pl-10 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
                <Search className="w-4 h-4 text-gray-400 absolute left-3 top-1/2 transform -translate-y-1/2" />
              </div>
            </div>

            {/* Date Filter */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <Calendar className="w-4 h-4 inline mr-1" />
                Date
              </label>
              <input
                type="date"
                value={filters.date}
                onChange={(e) => handleFilterChange('date', e.target.value)}
                className="w-full border border-gray-300 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              />
            </div>

            {/* Status Filter */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Status
              </label>
              <select
                value={filters.status}
                onChange={(e) => handleFilterChange('status', e.target.value)}
                className="w-full border border-gray-300 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              >
                {statusOptions.map(option => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between pt-4 border-t border-gray-200">
            {/* Checked Filter */}
            <div className="flex items-center">
              <motion.button
                onClick={() => handleFilterChange('checked', !filters.checked)}
                className="flex items-center space-x-3 text-sm text-gray-700 hover:text-gray-900 transition-colors"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                {filters.checked ? (
                  <CheckSquare className="w-5 h-5 text-blue-600" />
                ) : (
                  <Square className="w-5 h-5 text-gray-400" />
                )}
                <span className="font-medium">Show additional details</span>
              </motion.button>
            </div>

            {/* View Mode Toggle */}
            <div className="flex items-center gap-2 mt-4 sm:mt-0">
              <span className="text-sm text-gray-600">View:</span>
              <div className="flex bg-gray-100 rounded-lg p-1">
                <button
                  onClick={() => setViewMode('table')}
                  className={`px-3 py-1 rounded-lg text-sm font-medium transition-all ${
                    viewMode === 'table' 
                      ? 'bg-white text-blue-600 shadow-sm' 
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  Table
                </button>
                <button
                  onClick={() => setViewMode('cards')}
                  className={`px-3 py-1 rounded-lg text-sm font-medium transition-all ${
                    viewMode === 'cards' 
                      ? 'bg-white text-blue-600 shadow-sm' 
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  Cards
                </button>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Content */}
        <motion.div variants={cardVariants}>
          <AnimatePresence mode="wait">
            {loading ? (
              <motion.div 
                key="loading"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="flex items-center justify-center py-16"
              >
                <div className="flex items-center gap-3 text-blue-600">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                  <span className="text-lg font-medium">Loading leave history...</span>
                </div>
              </motion.div>
            ) : error ? (
              <motion.div 
                key="error"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                className="bg-red-50 border border-red-200 rounded-2xl p-8 text-center"
              >
                <XCircle className="w-12 h-12 text-red-500 mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-red-800 mb-2">Error Loading Data</h3>
                <p className="text-red-600">{error}</p>
              </motion.div>
            ) : filteredData.length === 0 ? (
              <motion.div 
                key="empty"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                className="bg-gray-50 border-2 border-dashed border-gray-300 rounded-2xl p-12 text-center"
              >
                <FileText className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-xl font-semibold text-gray-600 mb-2">No Leave History Found</h3>
                <p className="text-gray-500">Try adjusting your filters or search criteria.</p>
              </motion.div>
            ) : viewMode === 'table' ? (
              <TableView data={filteredData} filters={filters} getStatusBadge={getStatusBadge} />
            ) : (
              <CardsView data={filteredData} filters={filters} getStatusBadge={getStatusBadge} />
            )}
          </AnimatePresence>
        </motion.div>
      </motion.div>
    </div>
  );
};

// Enhanced Stats Card Component
const StatsCard = ({ icon: Icon, label, value, color }) => {
  const colorClasses = {
    blue: 'bg-blue-50 text-blue-600 border-blue-200',
